import React, { useState } from 'react';
import './App.css';
import Header from './components/Header';
import GeneratorForm from './components/GeneratorForm';
import NftPreview from './components/NftPreview';
import Footer from './components/Footer';

function App() {
  const [previewImage, setPreviewImage] = useState(null);

  // Mock function to generate an image preview (replace with real API integration)
  const handleGenerate = (description, style) => {
    // Here, you can add a call to your AI API that generates an NFT
    console.log(description, style);
    setPreviewImage('https://via.placeholder.com/600x400'); // Placeholder image
  };

  return (
    <div className="App">
      <Header />
      <GeneratorForm onGenerate={handleGenerate} />
      {previewImage && <NftPreview previewImage={previewImage} />}
      <Footer />
    </div>
  );
}

export default App;
